shortcuts.codeOnPrepare:
const currentUrl = getVariable('nas_url');
const nasUrlInput = prompt('Enter the full NAS address, including http:// or https:// and the port if needed.', currentUrl || 'http://192.168.0.20:8080');
if (nasUrlInput === null) abort();
const nasUrl = nasUrlInput.trim().replace(/\/+$/, '');
if (!/^https?:\/\/[^\s/]+(?::\d+)?(?:\/.*)?$/i.test(nasUrl)) {
  showDialog('Enter a complete address such as http://192.168.0.20:8080', 'Invalid NAS address');
  abort();
}
const nasIdInput = prompt('Enter the youtube-dl NAS login ID.', getVariable('nas_id'));
if (nasIdInput === null) abort();
const nasId = nasIdInput.trim();
if (!nasId) {
  showDialog('The login ID cannot be empty.', 'Missing login ID');
  abort();
}
const nasPassword = promptPassword('Enter the youtube-dl NAS login password.');
if (nasPassword === null) abort();
if (!nasPassword) {
  showDialog('The password cannot be empty.', 'Missing password');
  abort();
}
setVariable('nas_url', nasUrl);
setVariable('nas_id', nasId);
setVariable('nas_password', nasPassword);
showDialog('Saved. Now share a YouTube or video URL and choose Download to NAS.', 'youtube-dl NAS is ready');
abort();

const nasUrl = getVariable('nas_url').trim();
const nasId = getVariable('nas_id').trim();
const nasPassword = getVariable('nas_password');
if (!nasUrl || !nasId || !nasPassword) {
  showDialog('Open HTTP Shortcuts and run 1. Configure NAS first.', 'Setup required');
  abort();
}
const sharedText = getVariable('shared_text').trim();
let urlMatch = sharedText.match(/https?:\/\/[^\s]+/i);
if (!urlMatch) {
  const manualUrl = prompt('No link was detected in the Android share data. Paste the video URL here.', sharedText);
  if (manualUrl === null) abort();
  urlMatch = manualUrl.trim().match(/https?:\/\/[^\s]+/i);
}
if (!urlMatch) {
  showDialog('Enter a complete link beginning with http:// or https://.', 'URL missing');
  abort();
}
setVariable('request_url', urlMatch[0]);
